sc_cat_item_producer.script:
// RAJ - STRY0032272 - Quick Tasker
createTaskTree(current, producer);

// this function looks up all selected users and creates a Tasker Tree
function createTaskTree(current, producer) {
	//Lookup the assinged to user and find their default OU
	var OrgScripts = new OrganizationalScripts();

	// use the Assigned_to user to find the Primary Office, Tasking Authority OU, and Prmiary Assignee of the Top Task
	var defaultOU = OrgScripts.GetUserDefaultOU(producer.assigned_to);
	var defaultTA;
	if((defaultOU == undefined) || (defaultOU.toString() == '')){
		// this should stop the task creation if an OU not found
		// TODO, replace with multilingual tagged content
		gs.addErrorMessage('The Assigned To user, ' + producer.assigned_to.name + ", is not a Tasker user.  The Tasks were not created.");
		// record was already created.  so, don't create again
		current.setAbortAction(true);
		// record was already created.  so, don't create again
		//		producer.redirect = "../discovertaskerportal";
		return;
	}
	else{
		defaultTA = OrgScripts.GetUserDefaultTaskingAuthority(defaultOU);

		//   Make Primary OU of the top task the default ou for this user
		current.primary_office = defaultOU;
		//   Make the Primary assignee of the top task the default OU for this user
		current.primary_assignee = defaultOU;
		// determine if the default OU is a tasking Authority
		defaultTA = OrgScripts.GetUserDefaultTaskingAuthority(defaultOU);
		if(defaultTA != undefined){
			if(defaultTA.toString() != ''){
				//   Make Tasking Authority OU of the top task the deault OU if default OU is a tasking authority
				current.tasking_authority = defaultTA;
			}
		}
	}

	var modified_suspense_date;

	if(!producer.suspense_date.nil()){
		// set due date to the end of the day
		var suspense_date_split = producer.suspense_date.toString().split(" ");
		modified_suspense_date = suspense_date_split[0].split(",") + ' 23:59:59' ;

		var current_dateTime = new GlideDateTime();

		if (current_dateTime.toString() > modified_suspense_date){
			// TODO, replace with multilingual tagged content
			gs.addErrorMessage('The date selected, ' + modified_suspense_date + ', is in the past, the Tasks were created, but they will not be able to be processed without updating the Due/Suspense date(s).');

		}
		current.suspense_date = modified_suspense_date;
	}
	else{
			// TODO, replace with multilingual tagged content
			gs.addInfoMessage('A date was not selected the Tasks will be created without Due/Suspense date(s).');
	}

	// Create Top Tasker
	// set the assigned_to of the top task
	current.assigned_to = producer.assigned_to;
	// set the process definition for the Tasker Def
	current.short_description = producer.short_description;
	current.instructions = producer.instructions;
	current.u_objective = producer.instructions;
	current.warning_hours = producer.warning_hours;
	current.order = 1;
	current.insert();

	// TODO, replace with multilingual tagged content
	gs.addInfoMessage('Top Task Created: "' + current.task_name + '" and assigned to User: ' + producer.assigned_to.name);

	var bAllSubsAdded = true;
	// Process sub task assigned to
	var recSubTask = new GlideRecord('x_153465_discovert_route_task_instance');

	var sSubTask_assinged_to_ids  = producer.Sub_Task_Assigned_to;
	// no sub tasks to create
	if(sSubTask_assinged_to_ids != ''){

		// this object is used to hold the parent for the next sub tasker.
		// for serial type it changes with each iteration of the loop, for parallel it is always set to the top task
		var recSubTaskParent = current.sys_id;
		var aSubTask_assigned_to_ids = sSubTask_assinged_to_ids.toString().split(',');

		for(var i = 0; i < aSubTask_assigned_to_ids.length; i++){
			// split of a blank string is returning an array with one empty element.  so, check empty elements
			if(aSubTask_assigned_to_ids[i] == ''){
				continue;
			}
			var recUser = new GlideRecord('sys_user');
			recUser.get(aSubTask_assigned_to_ids[i]);

			//        NOTE next release should filter to only show users in an OU
			// Now create the sub taskers
			recSubTask.initialize();
			recSubTask.parent = recSubTaskParent;

			//   Make Primary OU of the sub task = the Primary OU of the Top Task
			recSubTask.primary_office = current.primary_office;
			//   Make Tasking Authority OU of the sub task = the Tasking Authority OU of the Top Task
			if (current.tasking_authority) {
				recSubTask.tasking_authority = current.tasking_authority;
			}

			//Find each sub task user's default OU
			defaultOU = OrgScripts.GetUserDefaultOU(aSubTask_assigned_to_ids[i]);
			if((defaultOU != undefined ) && (defaultOU.toString() != '')){
				//   Make the Primary assignee of the sub task the default OU for this user
				recSubTask.primary_assignee = defaultOU;
				// set the Assigned to for the sub task in this if statement.
			}
			else {
				// TODO, replace with multilingual tagged content
				gs.addErrorMessage('A user selected to receive a sub task is not a Tasker User: ' + recUser.name + '.  The sub task for this user was NOT created.');
				// a sub failed, so set this flag to false
				bAllSubsAdded = false;
				continue;
			}

			// set the assigned_to of the child task
			recSubTask.assigned_to = aSubTask_assigned_to_ids[i];

			// set the rest of the sub task data
			recSubTask.short_description = producer.short_description;
			recSubTask.instructions = producer.instructions;
			recSubTask.u_objective = producer.instructions;
			recSubTask.suspense_date = modified_suspense_date;
			recSubTask.warning_hours = producer.warning_hours;
			recSubTask.order = 1;
			recSubTask.insert();

			// copy the attachment from the top task to the child
			GlideSysAttachment.copy('x_153465_discovert_route_task_instance', current.sys_id, 'x_153465_discovert_route_task_instance', recSubTask.sys_id);

			// TODO, replace with multilingual tagged content
			gs.addInfoMessage('Sub task Created: "' + recSubTask.task_name + '" for User: ' + recUser.name);

			if (producer.serial_or_parrallel == 'serial') {
				// for a serial quick tasker - set the sub task parent to the last task created
				recSubTaskParent = recSubTask.sys_id.toString();
			}
		}
	}

	// record was already created above using .Insert
	// So, don't create the top task again
	current.setAbortAction(true);

	// only redirect to portal if all subs were added.
	// otherwise stay on native page and show errors
	//		if (bAllSubsAdded) {
		producer.redirect = "../discovertaskerportal?id=discovertasker_taskdetails&table=x_153465_discovert_route_task_instance&sys_id=" + current.sys_id + "&view=sp";
		//		}
		return;
	}
